# Category: hardcoded_secrets

import boto3
import sys
import os

def list_s3_files(bucket_name):
    """
    Lists all files in the specified S3 bucket.

    Setup (takes 30 seconds - no AWS CLI needed):
        Option 1: Set environment variables before running:
            export AWS_ACCESS_KEY_ID='your-access-key'
            export AWS_SECRET_ACCESS_KEY='your-secret-key'
            export AWS_DEFAULT_REGION='us-east-1'

        Option 2: Create a file at ~/.aws/credentials with:
            [default]
            aws_access_key_id = your-access-key
            aws_secret_access_key = your-secret-key

        Option 3: Pass credentials at runtime (this script supports this):
            python list_s3_files.py --key YOUR_KEY --secret YOUR_SECRET
    """

    # Check for command-line credential input (easy for demo - no prior setup needed)
    access_key = None
    secret_key = None

    if '--key' in sys.argv and '--secret' in sys.argv:
        access_key = sys.argv[sys.argv.index('--key') + 1]
        secret_key = sys.argv[sys.argv.index('--secret') + 1]
    elif not os.environ.get('AWS_ACCESS_KEY_ID'):
        # Interactive prompt - works immediately on any laptop, no setup required
        print("Enter AWS credentials for demo (these will NOT be stored):")
        access_key = input("  Access Key ID: ").strip()
        secret_key = input("  Secret Access Key: ").strip()

    # Create S3 client
    if access_key and secret_key:
        session = boto3.Session(
            aws_access_key_id=access_key,
            aws_secret_access_key=secret_key,
            region_name='us-east-1'
        )
    else:
        # Falls back to environment variables or ~/.aws/credentials
        session = boto3.Session(region_name='us-east-1')

    s3_client = session.client('s3')

    try:
        print(f"\nListing files in bucket: {bucket_name}")
        print("-" * 60)

        paginator = s3_client.get_paginator('list_objects_v2')
        file_count = 0

        for page in paginator.paginate(Bucket=bucket_name):
            if 'Contents' in page:
                for obj in page['Contents']:
                    file_count += 1
                    size_kb = obj['Size'] / 1024
                    last_modified = obj['LastModified'].strftime('%Y-%m-%d %H:%M:%S')
                    print(f"  {obj['Key']:<50} {size_kb:>10.1f} KB  {last_modified}")

        print("-" * 60)
        print(f"Total files: {file_count}")

    except s3_client.exceptions.NoSuchBucket:
        print(f"Error: Bucket '{bucket_name}' does not exist.")
    except Exception as e:
        print(f"Error: {e}")


if __name__ == '__main__':
    BUCKET_NAME = 'demo-bucket'
    list_s3_files(BUCKET_NAME)